ControlPropertyState.AutoRuleBindingString:
// Update work order to closed work order
Patch(
    tbl_mrl_workorder,
    LookUp(tbl_mrl_workorder,ID = varSelectedWorkOrder.ID),
    {
        status_workorder_dmp: {
            Id: 5,Value: "CLS"
        },
        remarks: txtChecklistRemarks_1.Value
    }
);

// Update work order assign to closed
ForAll(
    Filter(tbl_mrl_workorder_assign, workorder.Id = varSelectedWorkOrder.ID),
    Patch(
        tbl_mrl_workorder_assign,
        ThisRecord,
        {
            status: { Id: 6 , Value: "Closed" }
        }
    )
);

Set(isPopupVerify, false);

Navigate(WORKORDER_LIST,ScreenTransition.Fade);
